"""xgen 어댑터 — xgen Node 실행 함수를 mantis ToolSpec으로 변환.

xgen의 노드 클래스를 mantis의 ToolSpec으로 래핑하여
ToolRegistry에 등록하고, 에이전트/플로우 모드에서 실행할 수 있게 한다.
"""

from __future__ import annotations

import asyncio
import inspect
import logging
from typing import Any

from mantis.tools.decorator import ToolSpec

logger = logging.getLogger(__name__)


def xgen_node_to_toolspec(
    node_instance: Any,
    *,
    name: str | None = None,
    description: str | None = None,
) -> ToolSpec:
    """xgen Node 인스턴스를 mantis ToolSpec으로 변환.

    Args:
        node_instance: xgen Node 인스턴스 (execute 메서드 보유).
        name: 도구 이름. None이면 node의 nodeId 또는 클래스명 사용.
        description: 도구 설명. None이면 node의 nodeName 또는 docstring.

    Returns:
        mantis ToolSpec.
    """
    # 이름 추출
    tool_name = name or getattr(node_instance, "nodeId", None) or type(node_instance).__name__
    tool_name = tool_name.replace("/", "_").replace("-", "_")

    # 설명 추출
    tool_desc = (
        description
        or getattr(node_instance, "nodeName", None)
        or getattr(node_instance, "__doc__", None)
        or f"xgen node: {tool_name}"
    )

    # 파라미터 추출 — xgen Node의 inputs에서
    parameters: dict[str, Any] = {}
    inputs = getattr(node_instance, "inputs", [])
    for inp in inputs:
        port_id = getattr(inp, "id", None) or getattr(inp, "name", None)
        port_type = getattr(inp, "type", "STR")
        if port_id:
            parameters[port_id] = {
                "type": _xgen_type_to_json_type(str(port_type)),
                "description": f"xgen input: {port_id} ({port_type})",
            }

    # xgen Node의 parameters에서도 추가
    node_params = getattr(node_instance, "parameters", [])
    if isinstance(node_params, list):
        for param in node_params:
            param_name = getattr(param, "name", None) or getattr(param, "id", None)
            if param_name and param_name not in parameters:
                parameters[param_name] = {
                    "type": "string",
                    "description": f"xgen param: {param_name}",
                    "optional": True,
                }

    # execute 함수 래핑
    original_execute = node_instance.execute

    async def _wrapped_execute(**kwargs: Any) -> dict:
        try:
            if inspect.iscoroutinefunction(original_execute):
                result = await original_execute(**kwargs)
            else:
                result = await asyncio.get_event_loop().run_in_executor(
                    None, lambda: original_execute(**kwargs),
                )
            if isinstance(result, dict):
                return result
            return {"result": result}
        except Exception as e:
            logger.error("xgen node '%s' 실행 실패: %s", tool_name, e)
            return {"error": str(e)}

    return ToolSpec(
        name=tool_name,
        description=tool_desc,
        parameters=parameters,
        fn=_wrapped_execute,
        is_async=True,
    )


def xgen_nodes_to_toolspecs(
    node_instances: list[Any],
) -> list[ToolSpec]:
    """여러 xgen Node를 mantis ToolSpec 목록으로 일괄 변환."""
    specs = []
    for node in node_instances:
        try:
            spec = xgen_node_to_toolspec(node)
            specs.append(spec)
        except Exception as e:
            logger.warning("xgen node 변환 실패: %s — %s", type(node).__name__, e)
    return specs


def _xgen_type_to_json_type(xgen_type: str) -> str:
    """xgen 포트 타입을 JSON Schema 타입으로 변환."""
    mapping = {
        "STR": "string",
        "STREAM STR": "string",
        "STREAM STR|STR": "string",
        "INT": "integer",
        "FLOAT": "number",
        "BOOL": "boolean",
        "OBJECT": "object",
        "DICT": "object",
        "LIST": "array",
        "FILE": "array",
        "ANY": "string",
        "TOOL": "object",
        "MODEL": "object",
    }
    return mapping.get(xgen_type.upper(), "string")
